const body = $input.item.json.body || $input.item.json;

// NOVOS CAMPOS COM BACKWARD COMPATIBILITY
const adultos = parseInt(body.adultos) || parseInt(body.pax) || 0;
const criancas_6_10 = parseInt(body.criancas_6_10) || parseInt(body.kids) || 0;
const criancas_0_5 = parseInt(body.criancas_0_5) || 0;

// PAX TOTAL (Soma tudo para cálculo de mesas)
const pax = adultos + criancas_6_10 + criancas_0_5;
const pax_pagante = adultos + criancas_6_10; // Para estatística futura

const nome_cliente = body.nome_cliente || "Cliente Web";
const whatsapp_id = body.whatsapp_id || "Não informado";
const data_reserva = body.data_reserva || new Date().toISOString().split('T')[0];

// Lógica de Mesas e Cadeiras Extras
let mesasNeeded = Math.ceil(pax / 4);
let observacao = "";

if (pax > 4) {
  const remainder = pax % 4;
  if (remainder === 1) {
    mesasNeeded = mesasNeeded - 1;
    observacao = "1 Cadeira Adicional";
  } else if (remainder === 2) {
    mesasNeeded = mesasNeeded - 1;
    observacao = "2 Cadeiras Adicionais";
  }
}

// DATAS E ABAS
const daysMap = ['Domingo', 'Segunda', 'Terca', 'Quarta', 'Quinta', 'Sexta', 'Sabado'];
const dateParts = data_reserva.split('-'); 
const dateObj = new Date(dateParts[0], dateParts[1] - 1, dateParts[2]);
const dayOfWeek = dateObj.getDay();
const diaSemana = daysMap[dayOfWeek];

const sheetReservas = `Reservas_${diaSemana}`;
const sheetMesas = `Mesas_${diaSemana}`;

// LÓGICA DE FUTURO: Verifica se a data é desta semana ou futura
const hoje = new Date();
// Calcula próximo domingo (fim desta semana)
const proximoDomingo = new Date(hoje);
proximoDomingo.setDate(hoje.getDate() + (7 - hoje.getDay()));
proximoDomingo.setHours(23, 59, 59, 999);

let isFuture = false;
if (dateObj > proximoDomingo) {
    isFuture = true;
}

return {
  pax,
  adultos,
  criancas_6_10,
  criancas_0_5,
  mesasNeeded,
  nome_cliente,
  whatsapp_id,
  observacao,
  data_reserva,
  diaSemana,
  sheet_reservas: sheetReservas,
  sheet_mesas: sheetMesas,
  isFuture: isFuture
};

const info = $node["[JS] Calc Mesas"].json;
const generateID = () => Math.random().toString(36).substr(2, 9).toUpperCase();
const timestamp = new Date().toLocaleString('pt-BR');

// Formata detalhe PAX para observação se necessário ou mantém simples
// Vamos salvar detalhes em colunas separadas se a planilha permitir, 
// mas por segurança vamos adicionar no objeto.

return {
  Reserva_ID: generateID(),
  Nome_Cliente: info.nome_cliente,
  WhatsApp: info.whatsapp_id,
  Qtd_Pessoas: info.pax,
  Qtd_Adultos: info.adultos,
  Qtd_Criancas_Meia: info.criancas_6_10,
  Qtd_Criancas_Free: info.criancas_0_5,
  Mesas_Alocadas: "A Definir (Semana Seguinte)",
  Observacao: info.observacao,
  Timestamp: timestamp,
  Status: "Pré-Reserva (Futura)",
  _meta: {
    whatsapp_original: info.whatsapp_id,
    data_reserva: info.data_reserva, 
    sheet_reservas: "Reservas_Futuras"
  }
};

const allMesas = $input.all();
const info = $node["[JS] Calc Mesas"].json;

// FILTRAGEM MANUAL (Mais Segura)
// Garante que só pega mesas com Status "LIVRE" (Maiúsculo ou Minúsculo)
const mesasLivres = allMesas.filter(m => 
   m.json.Status && m.json.Status.toString().trim().toUpperCase() === 'LIVRE'
);

const generateID = () => Math.random().toString(36).substr(2, 9).toUpperCase();
const timestamp = new Date().toLocaleString('pt-BR');

// Lógica de Alocação
let mesasAlocadas = "Indisponível";
let idsToUpdate = [];
let isFull = false;

// Verifica se tem mesas suficientes
if (mesasLivres.length >= info.mesasNeeded) {
  const selected = mesasLivres.slice(0, info.mesasNeeded);
  mesasAlocadas = selected.map(m => m.json.Mesa_ID).join(", ");
  idsToUpdate = selected.map(m => m.json.Mesa_ID);
} else {
   // LOTADO — vai para fila de espera
   isFull = true;
   mesasAlocadas = "FILA DE ESPERA";
}

return {
  Reserva_ID: generateID(),
  Nome_Cliente: info.nome_cliente,
  WhatsApp: info.whatsapp_id,
  Qtd_Pessoas: info.pax,
  Qtd_Adultos: info.adultos,
  Qtd_Criancas_Meia: info.criancas_6_10,
  Qtd_Criancas_Free: info.criancas_0_5,
  Mesas_Alocadas: mesasAlocadas,
  Observacao: info.observacao,
  Timestamp: timestamp,
  Status: isFull ? "Na Fila" : "Pendente",
  _meta: {
    whatsapp_original: info.whatsapp_id,
    idsToUpdate, 
    sheet_reservas: isFull ? 'Fila_Espera' : info.sheet_reservas,
    sheet_mesas: info.sheet_mesas,
    data_reserva: info.data_reserva,
    isFull: isFull
  }
};

