const reserva = $input.first().json;
return {
  output: "Reserva (" + reserva.Status + ") confirmada para " + reserva.Nome_Cliente + "."
};

const meta = $input.first().json._meta || {};
const ids = meta.idsToUpdate || [];
const sheetMesas = meta.sheet_mesas || 'Mesas_Terca';
return ids.map(id => ({
  json: {
    Mesa_ID: isNaN(parseInt(id, 10)) ? id : parseInt(id, 10),
    Status: "RESERVADO",
    sheet_mesas: sheetMesas
  }
}));

const reserva = $node["[JS] Gerar Objeto Reserva"].json;
return {
  output: "Estamos lotados! " + reserva.Nome_Cliente + " entrou na fila de espera. Avisaremos quando abrir uma vaga. 🍕",
