      WhatsApp: item.json.WhatsApp,
      Qtd_Pessoas: item.json.Qtd_Pessoas,
      Qtd_Adultos: item.json.Qtd_Adultos,
      Qtd_Criancas_Meia: item.json.Qtd_Criancas_Meia,
      Qtd_Criancas_Free: item.json.Qtd_Criancas_Free,
      Mesas_Alocadas: item.json.Mesas_Alocadas,
      Observacao: item.json.Observacao,
      Timestamp: item.json.Timestamp,
      Status: item.json.Status,
      _meta: item.json._meta
    }
  };
});
return newItems;
